import toast from "react-hot-toast";
import { useEffect, useState } from "react";
import { useAppStore } from "../store/appStore";

export default function SettingsPage() {
  const { user, subscription, plans, settings, updateSettings, openWebsite, logout, fetchPlans, startSubscriptionCheckout } = useAppStore();
  const [purchasingPlan, setPurchasingPlan] = useState("");

  useEffect(() => {
    fetchPlans().catch(() => {
      toast.error("Failed to load plans");
    });
  }, [fetchPlans]);

  const toggle = async (key) => {
    await updateSettings({ [key]: !settings[key] });
    toast.success("Settings updated");
  };

  const onBuy = async (planKey) => {
    setPurchasingPlan(planKey);
    try {
      await startSubscriptionCheckout(planKey);
    } catch (error) {
      toast.error(error?.response?.data?.message || error.message || "Unable to start PayPal checkout");
    } finally {
      setPurchasingPlan("");
    }
  };

  return (
    <div className="grid gap-4 md:grid-cols-2">
      <div className="card">
        <h3 className="mb-3 text-lg font-semibold">Account</h3>
        <p className="text-sm">Email: {user?.email}</p>
        <p className="text-sm">Name: {user?.firstName} {user?.lastName}</p>
        <button className="mt-3 text-sm text-brand-700 hover:underline" onClick={() => openWebsite("/account/change-password")}>Change Password</button>
      </div>

      <div className="card">
        <h3 className="mb-3 text-lg font-semibold">Subscription</h3>
        <p className="text-sm">Plan: {subscription?.planType || "-"}</p>
        <p className="text-sm">Credits/Month: {subscription?.creditsPerMonth || "-"}</p>
        <p className="text-sm">Next Billing: {subscription?.nextBillingDate ? new Date(subscription.nextBillingDate).toLocaleDateString() : "-"}</p>
        <p className="mt-3 text-sm text-slate-500">Choose a plan below to subscribe with PayPal.</p>
      </div>

      <div className="card md:col-span-2">
        <h3 className="mb-3 text-lg font-semibold">Plans</h3>
        <div className="grid gap-4 md:grid-cols-3">
          {plans.map((plan) => (
            <div key={plan.key} className="rounded-xl border border-slate-200 bg-slate-50 p-4">
              <h4 className="text-base font-semibold">{plan.planType}</h4>
              <p className="mt-2 text-2xl font-bold text-slate-900">${plan.monthlyPrice}<span className="ml-1 text-sm font-normal text-slate-500">/ month</span></p>
              <p className="mt-2 text-sm text-slate-600">{plan.creditsPerMonth} credits per month</p>
              <button
                className="btn-primary mt-4 w-full"
                disabled={!plan.available || purchasingPlan === plan.key}
                onClick={() => onBuy(plan.key)}
              >
                {purchasingPlan === plan.key ? "Opening PayPal..." : plan.available ? "Buy with PayPal" : "Unavailable"}
              </button>
            </div>
          ))}
        </div>
        <button className="mt-4 text-sm text-brand-700 hover:underline" onClick={() => openWebsite("/account/change-password")}>Manage password on website</button>
      </div>

      <div className="card md:col-span-2">
        <h3 className="mb-3 text-lg font-semibold">App Settings</h3>
        <div className="space-y-2">
          <label className="flex items-center gap-2 text-sm">
            <input type="checkbox" checked={settings.autoUpdate} onChange={() => toggle("autoUpdate")} />
            Auto-check for updates
          </label>
          <label className="flex items-center gap-2 text-sm">
            <input type="checkbox" checked={settings.saveHistory} onChange={() => toggle("saveHistory")} />
            Save validation history
          </label>
        </div>
        <button className="btn-outline mt-4" onClick={logout}>Logout</button>
      </div>
    </div>
  );
}
